SERVICE_ROLE_KEY = os.environ.get("SUPABASE_SERVICE_ROLE_KEY", "")

def upsert_vcs(records):
    if not records: return 0
    url = f"{SUPABASE_URL}/rest/v1/vcs?on_conflict=name"
    h = {"apikey": SERVICE_ROLE_KEY, "Authorization": f"Bearer {SERVICE_ROLE_KEY}",
         "Content-Type": "application/json", "Prefer": "resolution=merge-duplicates,return=minimal"}
    r = requests.post(url, headers=h, json=records, timeout=30)
    if r.status_code not in (200, 201):
        print(f"  [WARN] {r.status_code}: {r.text[:200]}")
        return 0
    return len(records)

