def main():
    print(f"Batch 3: {len(BATCH3)} records")
    seen = set()
    deduped = [r for r in BATCH3 if r["name"].lower() not in seen and not seen.add(r["name"].lower())]
    print(f"After dedup: {len(deduped)}")

    total = 0
    for i in range(0, len(deduped), 50):
        loaded = upsert_vcs(deduped[i:i+50])
        total += loaded
        print(f"  Batch {i//50+1}: +{loaded}")

    print(f"Batch 3 done: {total}")

    h = {"apikey": SERVICE_ROLE_KEY, "Authorization": f"Bearer {SERVICE_ROLE_KEY}", "Prefer": "count=exact"}
    resp = requests.head(f"{SUPABASE_URL}/rest/v1/vcs?select=count", headers=h, timeout=10)
    print(f"Total: {resp.headers.get('content-range', 'unknown')}")


if __name__ == "__main__":
    main()
